#include <linux/usb/ch9.h>
#include <linux/usb/gadgetfs.h>
#include <linux/usb/gadget/dwc3.h>
#include <linux/usb/gadget/dwc3-gadget.h>

static void dwc3_gadget_giveback(struct usb_ep *ep, struct usb_request *req)
{
    struct dwc3_ep *dep = to_dwc3_ep(ep);
    struct dwc3_request *dr = to_dwc3_request(req);
    struct dwc3_gadget *gadget = to_dwc3_gadget(ep->gadget);
    unsigned long flags;

    spin_lock_irqsave(&gadget->lock, flags);

    if (req->status == -ESHUTDOWN) {
        spin_unlock_irqrestore(&gadget->lock, flags);
        return;
    }

    if (req->status == 0) {
        dr->status = 0;
    } else {
