#include <string.h>
#include <crypto/crypto_aead.h>

#define ESP_HDR_LEN 4

int esp_input(const uint8_t *data, size_t data_len, uint8_t *out, size_t out_len) {
    // Check input parameters
    if (data == NULL || data_len < ESP_HDR_LEN || out == NULL || out_len < data_len - ESP_HDR_LEN) {
        return -1;
    }

    // Set up scatter-gather lists for input and output
    struct scatterlist in_sg[2];
    struct scatterlist out_sg[2];

    // Set up input scatter-gather list
    in_sg[0].addr = (uint8_t *)data;
    in_sg[0].len = ESP_HDR_LEN;
    in_sg[1].addr = (uint8_t *)data + ESP_HDR_LEN;
    in_sg[1].len = data_len - ESP_HDR_LEN;

    // Set up output scatter-gather list
    out_sg[0].addr = out;
    out_sg[0].len = out_len;

    // Decrypt ESP packet
    int ret = crypto_aead_decrypt(out_sg, in_sg, out_len, NULL, 0, NULL, 0, NULL);
    if (ret < 0) {
        return ret;
    }

    return 0;
}
