std::vector<Node> addNodes(const std::vector<std::string>& links, const std::vector<std::string>& subscriptions) {
  std::vector<Node> nodes;

  for (const auto& link : links) {
    std::smatch match;
    std::regex_search(link, match, std::regex("^([^:]+):([^:]+)$"));
    if (match.size() != 3) {
      std::cerr << "Invalid link format: " << link << std::endl;
      continue;
    }

    std::string name = match[1];
    std::string type = match[2];
    std::string address = link.substr(match[0].length());

    if (type == "SOCKS") {
      // Handle SOCKS link type
    } else if (type == "HTTP") {
      // Handle HTTP link type
    } else if (type == "FILE") {
      // Handle local file link type
    } else {
      std::cerr << "Unknown link type: " << type << std::endl;
      continue;
    }

    // Check if node is in subscriptions
    if (std::find(subscriptions.begin(), subscriptions.end(), name) == subscriptions.end()) {
      continue;
    }

    nodes.push_back({name, type, address});
  }

  return nodes;
}

int main() {
  std::vector<std::string> links = {"SOCKS:127.0.0.1:1080", "HTTP:www.example.com", "FILE:/path/to/file"};
  std::vector<std::string> subscriptions = {"SOCKS", "HTTP"};
  auto nodes = addNodes(links, subscriptions);
