#include <string.h>
#include <rpm/rpmfi.h>
#include <rpm/rpmfiles.h>
#include <rpm/rpmpsm.h>

int fsmMkfile(const char *filename, const char *content) {
    int ret = 0;
    rpmfi fi;
    rpmfiles files;
    rpmpsm psms;
    char *filepath;
    char *filecontent;
    size_t filecontent_len;

    // Initialize the file system interface
    if ((ret = rpmfiInit(&fi, NULL)) != 0) {
        fprintf(stderr, "rpmfiInit failed: %s\n", strerror(ret));
        return ret;
    }

    // Get the file path and content
    filepath = rpmfiGetPath(&fi, filename);
    filecontent = rpmfiGetContent(&fi, filename);
    filecontent_len = strlen(filecontent);

    // Create the file
    if ((ret = rpmfilesCreate(&files, filepath, filecontent, filecontent_len)) != 0) {
        fprintf(stderr, "rpmfilesCreate failed: %s\n", strerror(ret));
        goto cleanup;
    }

    // Check if the file is a hardlink
    if ((ret = rpmfiIsHardlink(&fi, filename)) == 1) {
        // Get the hardlink information
        rpmfiGetHardlinkInfo(&fi, filename, &psms);

        // Create the hardlink
        if ((ret = rpmpsmCreate(&psms, filepath, filecontent, filecontent_len)) != 0) {
            fprintf(stderr, "rpmpsmCreate failed: %s\n", strerror(ret));
            goto cleanup;
        }
    }

cleanup:
    // Clean up
    rpmfiFree(&fi);
    rpmfilesFree(&files);
    rpmpsmFree(&psms);
    free(filepath);
    free(filecontent);

    return ret;
}
