#include <QFile>
#include <QDir>
#include <QZipReader>
#include <QTextCodec>

void UnZip(const QString &zipFilePath, const QString &destinationDir) {
    QFile zipFile(zipFilePath);
    QDir destinationDir(destinationDir);

    if (!zipFile.open(QIODevice::ReadOnly)) {
        qDebug() << "Error opening ZIP file: " << zipFile.errorString();
        return;
    }

    QZipReader zipReader(&zipFile);
    QStringList fileNames = zipReader.fileNameList();

    for (const QString &fileName : fileNames) {
        QString filePath = destinationDir.filePath(fileName);
        QFileInfo fileInfo(filePath);

        if (fileInfo.isDir()) {
            QDir dir(filePath);
            dir.mkpath(".");
        } else {
            QFile file(filePath);
            QTextCodec *codec = QTextCodec::codecForName("IBM437");
            QByteArray data = zipReader.fileData(fileName);
            QString text = codec->toUnicode(data);
            file.open(QIODevice::WriteOnly | QIODevice::Text);
            QTextStream stream(&file);
            stream << text;
            file.close();
        }
    }

    zipFile.close();
}
