int WritePALMImage(const char *filename, unsigned char *data, size_t size,
                    unsigned char compression, unsigned char transparency) {
    FILE *fp = fopen(filename, "wb");
    if (!fp) {
        fprintf(stderr, "Failed to open file %s for writing\n", filename);
        return 1;
    }

    palm_image_t *image = malloc(sizeof(palm_image_t) + size);
    if (!image) {
        fprintf(stderr, "Failed to allocate memory for PALM image\n");
        fclose(fp);
        return 1;
    }

    image->magic[0] = PALM_IMAGE_MAGICK_NUMBER;
    image->version[0] = PALM_IMAGE_VERSION;
    image->width[0] = size >> 24;
    image->width[1] = size >> 16;
    image->width[2] = size >> 8;
    image->width[3] = size;
    image->height[0] = size >> 24;
    image->height[1] = size >> 16;
    image->height[2] = size >> 8;
    image->height[3] = size;
    image->compression[0] = compression;
    image->transparency[0] = transparency;
    image->unused[0] = 0;
    image->unused[1] = 0;
    image->unused[2] = 0;
    image->unused[3] = 0;
    memcpy(image->data, data, size);

    size_t written = fwrite(image, sizeof(palm_image_t) + size, 1, fp);
    if (written != 1) {
        fprintf(stderr, "Failed to write PALM image to file %s\n", filename);
        free(image);
        fclose(fp);
        return 1;
    }

    fclose(fp);
    free(image);
