#include <random>

using namespace Eigen;
using namespace std;

// PhiloxRandom generator
struct PhiloxRandom {
  PhiloxRandom(int seed) : gen(seed) {}

  int operator()() {
    return gen();
  }

private:
  std::mt19937 gen;
};

// Vectorized uniform rejection sampling
template <typename T>
void vectorized_uniform_rejection_sampling(const Matrix<T, Dynamic, 1>& a, const Matrix<T, Dynamic, 1>& b, Matrix<T, Dynamic, 1>& x, PhiloxRandom& gen) {
  // Get the number of samples and dimensions
  int n = x.size();
  int d = x.cols();

  // Initialize the uniform distribution
  std::uniform_real_distribution<T> dist(0, 1);

  // Generate random numbers for each dimension
  for (int i = 0; i < d; ++i) {
    // Generate a random number between 0 and 1
    T r = dist(gen);

    // Compute the corresponding interval
    T interval = (b(i) - a(i)) * r;

    // Sample the interval
    x(i) = a(i) + interval;
  }
}

int main() {
  // Initialize the PhiloxRandom generator
  PhiloxRandom gen(1234);

  // Define the bounds of the uniform distribution
  Matrix<double, Dynamic, 1> a = {0, 0};
  Matrix<double, Dynamic, 1> b = {1, 1};

  // Define the number of samples and dimensions
  int n = 1000;
  int d = 2;

  // Allocate memory for the samples
  Matrix<double, Dynamic, 1> x(n, d);

  // Perform vectorized uniform rejection sampling
  vectorized_uniform_rejection_sampling(a, b, x, gen);

  // Print the samples
  cout << "Samples: " << endl;
  cout << x << endl;

  return 0;
}
