#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <llhttp.h>

#define BUFFER_SIZE 1024

struct http_parser_settings settings;
struct http_parser parser;

void on_message_begin(http_parser *parser) {
  printf("Message begin\n");
}

void on_url(http_parser *parser, const char *at, size_t length) {
  printf("URL: %.*s\n", (int)length, at);
}

void on_status(http_parser *parser, const char *at, size_t length) {
  printf("Status: %.*s\n", (int)length, at);
}

void on_header_field(http_parser *parser, const char *at, size_t length) {
  printf("Header field: %.*s\n", (int)length, at);
}

void on_header_value(http_parser *parser, const char *at, size_t length) {
  printf("Header value: %.*s\n", (int)length, at);
}

void on_headers_complete(http_parser *parser) {
  printf("Headers complete\n");
}

void on_body(http_parser *parser, const char *at, size_t length) {
  printf("Body: %.*s\n", (int)length, at);
}

void on_message_complete(http_parser *parser) {
  printf("Message complete\n");
}

int main(void) {
  char buffer[BUFFER_SIZE];
  size_t nparsed;

  http_parser_init(&parser, HTTP_REQUEST);
  http_parser_settings_init(&settings);

  settings.on_message_begin = on_message_begin;
  settings.on_url = on_url;
  settings.on_status = on_status;
  settings.on_header_field = on_header_field;
  settings.on_header_value = on_header_value;
  settings.on_headers_complete = on_headers_complete;
  settings.on_body = on_body;
  settings.on_message_complete = on_message_complete;

  while (1) {
    printf("Enter HTTP message: ");
    fgets(buffer, BUFFER_SIZE, stdin);
    nparsed = http_parser_execute(&parser, &settings, buffer, strlen(buffer));
    if (nparsed != strlen(buffer)) {
      fprintf(stderr, "Error parsing HTTP message\n");
      break;
    }
  }

  return 0;
}

