{
    struct sock *newsk;
    struct ipv6_pinfo *np;
    struct inet_request_sock *ireq;
    struct ipv6_opt_hdr *hdr;
    struct ipv6_txoptions *opt;
    int err;

    newsk = inet6_csk_clone_lock(sk, req->rsk_ops->family);
    if (!newsk)
