    np->rxopt.bits.rxoinfo = 1;
    np->rxopt.bits.rxhlim = 1;
    np->rxopt.bits.rxohlim = 1;
    np->mcast_oif = sk->sk_bound_dev_if;
    np->mcast_hops = 1;

    ireq = inet_rsk(req);
    ireq->pktopts = NULL;
    ireq->opt = NULL;

    if (skb->protocol == htons(ETH_P_IPV6)) {
        hdr = (struct ipv6_opt_hdr *)skb_transport_header(skb);
        opt = ipv6_dup_options(skb, hdr);
        if (!opt) {
            err = -ENOMEM;
            goto error;
        }
        np->opt = opt;
        np->pktoptions = opt;
    }

    return newsk;

