#define NS_CLONE_NEWIPC 0x08000000
#define NS_CLONE_NEWNET 0x40000000
#define NS_CLONE_NEWNS 0x20000000
#define NS_CLONE_NEWPID 0x20000000
#define NS_CLONE_NEWUTS 0x04000000

int nsexec(int flags, void *(*func)(void *), void *arg) {
    int sock[2];
    if (socketpair(AF_UNIX, SOCK_STREAM, 0, sock) < 0) {
        return -1;
    }

    pid_t pid = clone(func, arg, flags | NS_CLONE_NEWIPC | NS_CLONE_NEWNET | NS_CLONE_NEWNS | NS_CLONE_NEWPID | NS_CLONE_NEWUTS, sock);
    if (pid < 0) {
        close(sock[0]);
        close(sock[1]);
        return -1;
    }

    if (prctl(PR_SET_DUMPABLE, 0, 0, 0, 0) < 0) {
        close(sock[0]);
        close(sock[1]);
        return -1;
    }

    close(sock[1]);
    return waitpid(pid, NULL, 0);
}
