static void
e_ews_autodiscover_ws_url_async (SoupSession *session,
                                  const gchar *domain,
                                  GCancellable *cancellable,
                                  GAsyncReadyCallback callback,
                                  gpointer user_data)
{
  GSimpleAsyncResult *result = g_simple_async_result_new (G_OBJECT (session),
                                                          cancellable,
                                                          callback,
                                                          user_data);
  g_simple_async_result_set_op_res_gpointer (result,
                                             e_ews_autodiscover_ws_url_finish,
                                             NULL);

  SoupURI *uri = soup_uri_new ("https", domain, "/autodiscover/autodiscover.xml");
  SoupMessage *msg = soup_message_new ("GET", uri);
  soup_uri_free (uri);

  soup_message_set_flags (msg, SOUP_MESSAGE_CANCELABLE);
  soup_session_queue_message (session, msg, e_ews_autodiscover_ws_url_finish, result);
}

static void
e_ews_autodiscover_ws_url_finish (SoupSession *session,
                                  SoupMessage *msg,
                                  GAsyncResult *result)
{
  GSimpleAsyncResult *simple = G_SIMPLE_ASYNC_RESULT (result);
  gpointer user_data = g_simple_async_result_get_op_res_gpointer (simple);
  gchar *ws_url = NULL;

  if (msg->status_code == SOUP_STATUS_OK)
    {
      xmlDoc *doc = soup_xml_response_body_to_doc (msg);
      xmlNode *node = xmlDocGetRootElement (doc);
      xmlNode *child = node->children;

      while (child)
        {
          if (child->type == XML_ELEMENT_NODE &&
              xmlStrEqual (child->name, (const xmlChar *) "Url"))
            {
              xmlChar *url = xmlNodeGetContent (child);
              ws_url = g_strdup (url);
              xmlFree (url);
              break;
            }
          child = child->next;
        }
      xmlFreeDoc (doc);
    }

  g_simple_async_result_set_op_res_gpointer (simple, ws_url, NULL);
  g_simple_async_result_complete_in_idle (simple);
}

gchar *
e_ews_autodiscover_ws_url (SoupSession *session,
                           const gchar *domain,
                           GCancellable *cancellable,
                           GError **error)
{
  GSimpleAsyncResult *result = NULL;
  gchar *ws_url = NULL;

  e_ews_autodiscover_ws_url_async (session, domain, cancellable,
                                   (GAsyncReadyCallback) e_ews_autodiscover_ws_url_finish,
                                   &result);
  g_simple_async_result_wait (result, cancellable, error);
  ws_url = g_simple_async_result_get_op_res_gpointer (result);
  g_object_unref (result);

  return ws_url;
}
