namespace tensorflow {

class UnsortedSegmentReductionOp : public OpKernel {
 public:
  explicit UnsortedSegmentReductionOp(OpKernelConstruction* context)
      : OpKernel(context) {}

  void Compute(OpKernelContext* context) override {
    const Tensor& data = context->input(0);
    const Tensor& segment_ids = context->input(1);
    const Tensor& num_segments = context->input(2);

    OP_REQUIRES(context, TensorShapeUtils::IsVector(segment_ids.shape()),
                errors::InvalidArgument("segment_ids must be a vector."));
    OP_REQUIRES(context, TensorShapeUtils::IsScalar(num_segments.shape()),
                errors::InvalidArgument("num_segments must be a scalar."));

    int64_t num_segments_value = num_segments.scalar<int64_t>()();
    OP_REQUIRES(context, num_segments_value > 0,
                errors::InvalidArgument("num_segments must be positive."));

    TensorShape output_shape({num_segments_value, data.dim_size(1)});
    Tensor* output = nullptr;
    OP_REQUIRES_OK(context, context->allocate_output(0, output_shape, &output));

    auto data_flat = data.flat<float>();
    auto segment_ids_flat = segment_ids.flat<int32>();
    auto output_flat = output->flat<float>();

    for (int64_t i = 0; i < num_segments_value; ++i) {
      int32_t segment_id = segment_ids_flat(i);
      OP_REQUIRES(context, segment_id >= 0 && segment_id < num_segments_value,
                  errors::InvalidArgument("segment_id must be in [0, num_segments)."));
      for (int64_t j = 0; j < data.dim_size(1); ++j) {
        output_flat(i, j) = data_flat(segment_id, j);
      }
    }
  }
};

REGISTER_KERNEL_BUILDER(Name("UnsortedSegmentReduction").Device(DEVICE_CPU),
                        UnsortedSegmentReductionOp);

}  // namespace tensorflow
