gboolean
spawn_process (const gchar * arg_cwd_path,
               const gchar * arg_argv[],
               const gchar * arg_flags,
               GUnixFDList * arg_fd_list,
               GError ** error)
{
  gboolean ret = FALSE;
  GUnixFDList *fd_list = NULL;
  gchar **argv = NULL;
  gchar *cwd_path = NULL;
  gchar *flags = NULL;
  gint fd = -1;
  gint i = 0;
  gint j = 0;

  if (arg_cwd_path)
    cwd_path = g_strdup (arg_cwd_path);
  if (arg_argv)
    argv = g_strdupv (arg_argv);
  if (arg_flags)
    flags = g_strdup (arg_flags);

  if (arg_fd_list)
    fd_list = g_unix_fd_list_new ();

  if (cwd_path && argv && flags)
    {
      ret = TRUE;
      for (i = 0; argv[i]; i++)
        {
          if (strcmp (argv[i], "--") == 0)
            {
              argv[i] = NULL;
              break;
            }
        }
      for (j = 0; argv[j]; j++)
        {
          if (strcmp (argv[j], "--") == 0)
            {
              argv[j] = NULL;
              break;
            }
        }
      if (i == j)
        {
          g_set_error (error, G_IO_ERROR, G_IO_ERROR_INVALID_ARGUMENT,
                       "Invalid argument: %s", argv[i]);
          ret = FALSE;
        }
      else
        {
          fd = g_unix_open_pipe (&fd_list, O_CLOEXEC, error);
          if (fd == -1)
            {
              ret = FALSE;
            }
          else
            {
              g_spawn_async_with_pipes (cwd_path, argv, flags,
                                        G_SPAWN_DO_NOT_REAP_CHILD,
                                        NULL, NULL, NULL, NULL,
                                        &fd_list, NULL, NULL, error);
              if (g_error_matches (error, G_IO_ERROR, G_IO_ERROR_INVALID_ARGUMENT))
                {
                  ret = FALSE;
                }
              else
                {
                  g_unix_fd_list_append (fd_list, fd, error);
                  if (g_error_matches (error, G_IO_ERROR, G_IO_ERROR_INVALID_ARGUMENT))
                    {
                      ret = FALSE;
                    }
                }
            }
        }
    }
  else
    {
      g_set_error (error, G_IO_ERROR, G_IO_ERROR_INVALID_ARGUMENT,
                   "Invalid argument: %s", arg_cwd_path);
      ret = FALSE;
    }

  if (fd_list)
    g_object_unref (fd_list);
  if (argv)
    g_strfreev (argv);
  if (cwd_path)
    g_free (cwd_path);
  if (flags)
    g_free (flags);

  return ret;
