typedef struct {
    int socket;
    char buffer[BUFFER_SIZE];
} client_t;

pthread_mutex_t lock_request;

void *_handle_single_connection(void *arg) {
    client_t *client = (client_t *)arg;
    char *message = "Hello, world!\n";
    int bytes_sent;

    pthread_mutex_lock(&lock_request);
    bytes_sent = send(client->socket, message, strlen(message), 0);
    pthread_mutex_unlock(&lock_request);

    if (bytes_sent == -1) {
        perror("send");
        exit(1);
    }

    close(client->socket);
    free(client);
    return NULL;
}

int main(int argc, char *argv[]) {
    int server_fd, client_fd;
    struct sockaddr_in server_addr, client_addr;
    socklen_t client_len = sizeof(client_addr);
    pthread_t thread;
    client_t *client;

    if (argc != 2) {
        fprintf(stderr, "Usage: %s <port>\n", argv[0]);
        exit(1);
    }

    server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd == -1) {
        perror("socket");
        exit(1);
    }

    memset(&server_addr, 0, sizeof(server_addr));
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = htonl(INADDR_ANY);
    server_addr.sin_port = htons(atoi(argv[1]));

    if (bind(server_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) == -1) {
        perror("bind");
        exit(1);
    }

    if (listen(server_fd, MAX_CLIENTS) == -1) {
        perror("listen");
        exit(1);
    }

    while (1) {
        client_fd = accept(server_fd, (struct sockaddr *)&client_addr, &client_len);
        if (client_fd == -1) {
            perror("accept");
            exit(1);
        }

        client = (client_t *)malloc(sizeof(client_t));
        client->socket = client_fd;

        pthread_mutex_lock(&lock_request);
        pthread_create(&thread, NULL, _handle_single_connection, (void *)client);
        pthread_mutex_unlock(&lock_request);
    }

    return 0;
