#include <stdlib.h>
#include <string.h>
#include <openssl/sha.h>

#define FLOW_HASH_SECRET_SIZE 32

uint32_t flow_hash_from_keys(const char *keys) {
  uint32_t hash;
  uint8_t secret[FLOW_HASH_SECRET_SIZE];
  uint8_t hash_bytes[SHA256_DIGEST_LENGTH];

  // Generate a random secret for the hash
  if (RAND_bytes(secret, FLOW_HASH_SECRET_SIZE) != 1) {
    return 0;
  }

  // Compute the hash using the secret and the keys
  SHA256_CTX ctx;
  SHA256_Init(&ctx);
  SHA256_Update(&ctx, secret, FLOW_HASH_SECRET_SIZE);
  SHA256_Update(&ctx, keys, strlen(keys));
  SHA256_Final(hash_bytes, &ctx);

  // Return the hash
  memcpy(&hash, hash_bytes, sizeof(hash));
  return hash;
}
```
