#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <magick/api.h>

#define MAX_IMAGES 10

int main(int argc, char **argv) {
    MagickWand *wand;
    MagickWand *image;
    MagickWand *thumb;
    char *images[MAX_IMAGES];
    char *output;
    int i;

    if (argc < 3) {
        fprintf(stderr, "Usage: %s <input_file> <output_file>\n", argv[0]);
        return 1;
    }

    wand = NewMagickWand();
    image = NewMagickWand();
    thumb = NewMagickWand();

    for (i = 1; i < argc; i++) {
        images[i - 1] = argv[i];
    }

    output = argv[argc - 1];

    for (i = 0; i < MAX_IMAGES; i++) {
        if (images[i] == NULL) {
            break;
        }

        MagickReadImage(wand, images[i]);
        MagickAutoOrientImage(wand);
        MagickSetImageAlphaChannel(wand, MagickAlphaChannel);
        MagickSetImageBackgroundColor(wand, "white");
        MagickSetImageAlpha(wand, 0);
        MagickSetImageDepth(wand, 8);
        MagickSetImageFormat(wand, "png");
        MagickWriteImage(wand, images[i]);
        MagickResetIterator(wand);
        MagickGetImage(wand, &image);
        MagickGetImageAlphaChannel(wand, &thumb);
        MagickCompositeImage(wand, thumb, MagickOverCompositeOp, MagickTrue);
        MagickDestroyImage(thumb);
        MagickDestroyImage(image);
    }

    MagickWriteImages(wand, output, MagickTrue);
    MagickDestroyWand(wand);

    return 0;
}

