#include <stdlib.h>
#include <string.h>
#include <regex.h>
#include <proftime.h>
#include <mch.h>

int regmatch(const char *pattern, const char *string, int timeout)
{
    regex_t re;
    regmatch_t pmatch[1];
    int err;
    proftime_T start, end;
    int result;

    if (timeout > 0) {
        start = proftime_T();
    }

    err = regcomp(&re, pattern, REG_EXTENDED | REG_NEWLINE);
    if (err) {
        mch_errmsg(regerror(err, &re, NULL, 0));
        return -1;
    }

    result = regexec(&re, string, 1, pmatch, 0);
    regfree(&re);

    if (timeout > 0) {
        end = proftime_T();
        if (proftime_cmp(&end, &start, >)) {
            mch_errmsg("Timeout exceeded");
            return -1;
        }
    }

    return result;
}
