    entrypoints = R_NEWS(RBinAddr, r_list_length(entrypoint_list));
    if (!entrypoints) {
        return NULL;
    }

    iter = r_list_iterator(entrypoint_list);
    if (!iter) {
        return NULL;
    }

    for (; iter; iter = r_list_iterator_next(iter)) {
        entrypoint = r_list_iter_get(iter);
        if (!entrypoint) {
            continue;
        }

        entrypoints[entrypoint->offset] = *entrypoint;
    }

    r_list_free(entrypoint_list);
    return entrypoints;
