#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_REG_LEN 10
#define MAX_CMD_LEN 100

struct register_info {
    char name[MAX_REG_LEN];
    char value[MAX_REG_LEN];
};

struct command_info {
    char name[MAX_CMD_LEN];
    char value[MAX_CMD_LEN];
};

struct register_info *cmdline_insert_reg(struct register_info *regs, int *num_regs,
                                          struct command_info *cmd) {
    if (cmd->name[0] != 'r') {
        fprintf(stderr, "Invalid command: %s\n", cmd->name);
        return NULL;
    }

    char *reg_name = cmd->name + 1;
    char *reg_value = cmd->value;

    if (strlen(reg_name) > MAX_REG_LEN) {
        fprintf(stderr, "Register name too long: %s\n", reg_name);
        return NULL;
    }

    if (strlen(reg_value) > MAX_REG_LEN) {
        fprintf(stderr, "Register value too long: %s\n", reg_value);
        return NULL;
    }

    for (int i = 0; i < *num_regs; i++) {
        if (strcmp(regs[i].name, reg_name) == 0) {
            fprintf(stderr, "Register already exists: %s\n", reg_name);
            return NULL;
        }
    }

    if (!is_valid_register_name(reg_name)) {
        fprintf(stderr, "Invalid register name: %s\n", reg_name);
        return NULL;
    }

    if (!is_valid_register_value(reg_value)) {
        fprintf(stderr, "Invalid register value: %s\n", reg_value);
        return NULL;
    }

    struct register_info *new_regs = realloc(regs, (*num_regs + 1) * sizeof(struct register_info));
    if (new_regs == NULL) {
        fprintf(stderr, "Failed to allocate memory for new register\n");
        return NULL;
    }

    regs = new_regs;
    regs[*num_regs].name = reg_name;
    regs[*num_regs].value = reg_value;
    *num_regs += 1;

    return regs;
}

bool is_valid_register_name(char *reg_name) {
    for (int i = 0; i < strlen(reg_name); i++) {
        if (!isalnum(reg_name[i]) && reg_name[i] != '_') {
            return false;
        }
    }
    return true;
}

bool is_valid_register_value(char *reg_value) {
    for (int i = 0; i < strlen(reg_value); i++) {
        if (!isalnum(reg_value[i]) && reg_value[i] != '_') {
            return false;
        }
    }
    return true;
}
