#include <mowgli.h>

void destroy_session(struct sasl_session *session) {
    mowgli_node_t *node;
    mowgli_node_t *next;

    // Log the session destruction
    mowgli_log(LOG_INFO, "Destroying SASL session %p", session);

    // Free the session's memory
    mowgli_free(session);

    // Free the session's nodes
    node = session->nodes;
    while (node != NULL) {
        next = node->next;
        mowgli_free(node);
        node = next;
    }
}
