void installService(const wchar_t* filePath, const wchar_t* displayName)
{
    // Create a new service
    SC_HANDLE service = CreateService(
        SC_MANAGER_ALL_ACCESS,
        SERVICE_WIN32_OWN_PROCESS,
        displayName,
        SERVICE_START_PENDING,
        SERVICE_ERROR_IGNORE,
        SERVICE_AUTO_START,
        SERVICE_DEMAND_START,
        SERVICE_ERROR_IGNORE,
        filePath,
        NULL,
        NULL,
        NULL,
        NULL,
        NULL
    );

    if (service == NULL)
    {
        std::cout << "Failed to create service: " << GetLastError() << std::endl;
        return;
    }

    // Set the service to restart on failure
    SERVICE_FAILURE_ACTIONS failureActions = {0};
    failureActions.dwResetPeriod = 10;
    failureActions.lpRebootMsg = L"The service has failed and will be restarted.";
    failureActions.lpCommand = L"";
    failureActions.cActions = 1;
    failureActions.lpsaActions = &failureActions.Actions[0];
    failureActions.Actions[0].Type = SC_ACTION_RESTART;
    failureActions.Actions[0].Delay = 10;
    failureActions.Actions[0].Count = 1;

    if (!ChangeServiceConfig2(service, SERVICE_CONFIG_FAILURE_ACTIONS, &failureActions))
    {
        std::cout << "Failed to set service failure actions: " << GetLastError() << std::endl;
        CloseServiceHandle(service);
        return;
    }

    // Start the service
    if (!StartService(service, 0, NULL))
    {
        std::cout << "Failed to start service: " << GetLastError() << std::endl;
        CloseServiceHandle(service);
        return;
    }

    // Close the service handle
    CloseServiceHandle(service);
}
